css:
.vbes-benefits {
  padding: 72px 24px;
  text-align: center;
}
.vbes-benefits__heading {
  font-size: 2.25rem;
  font-weight: 700;
  margin: 0 0 12px;
  color: #1a1a1a;
}
.vbes-benefits__subtext {
  font-size: 1.1rem;
  color: #666;
  max-width: 600px;
  margin: 0 auto 48px;
  line-height: 1.6;
}
.vbes-benefits__grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 28px;
  max-width: 1100px;
  margin: 0 auto;
}
.vbes-benefits__card {
  background: #fff;
  border: 1px solid #e8e8e8;
  border-radius: 12px;
  padding: 36px 28px;
  text-align: left;
  transition: box-shadow 0.2s;
}
.vbes-benefits__card:hover {
  box-shadow: 0 4px 20px rgba(0,0,0,0.08);
}
.vbes-benefits__icon {
  font-size: 2rem;
  margin-bottom: 16px;
}
.vbes-benefits__title {
  font-size: 1.15rem;
  font-weight: 600;
  margin: 0 0 8px;
  color: #1a1a1a;
}
.vbes-benefits__desc {
  font-size: 0.95rem;
  line-height: 1.6;
  color: #555;
  margin: 0;
}
@media (max-width: 600px) {
  .vbes-benefits { padding: 48px 16px; }
  .vbes-benefits__heading { font-size: 1.75rem; }
}
